parameters.jsCode:
const items = $input.all();

return items.map(item => {
  const promptOriginal = item.json.prompt || '';

  const promptLimpio = promptOriginal.replace(/["']/g, '');

  return {
    json: {
      ...item.json,
      prompt_limpio: promptLimpio
    }
  };
});

